module signal_generator
(
    input clk,
    input rst_n,
    output reg [4:0] wave
);

reg state;

always @(*) begin
    case(state)
        0: begin
            if (wave == 31)
                state <= 1;
            else
                state <= 0;
        end
        1: begin
            if (wave == 0)
                state <= 0;
            else
                state <= 1;
        end
        default: state <= 0;
    endcase
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n)
        wave <= 5'b0;
    else begin
        case(state)
            0: begin
                if (wave == 31)
                    wave <= 5'b0;
                else
                    wave <= wave + 1;
            end
            1: begin
                if (wave == 0)
                    wave <= 5'b31;
                else
                    wave <= wave - 1;
            end
            default: wave <= 5'b0;
        endcase
    end
end
endmodule
